def create_self_signed_cert(key_size=2048):
    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=key_size,
        backend=default_backend()
    )
    
    subject = issuer = Name([
        NameAttribute(oid.NameOID.COUNTRY_NAME, "US"),
        NameAttribute(oid.NameOID.STATE_OR_PROVINCE_NAME, "California"),
        NameAttribute(oid.NameOID.LOCALITY_NAME, "San Francisco"),
        NameAttribute(oid.NameOID.ORGANIZATION_NAME, "Internal Identity Provider"),
        NameAttribute(oid.NameOID.COMMON_NAME, "internal-idp.example.com"),
    ])
    
    cert = x509.CertificateBuilder().subject_name(
        subject
    ).issuer_name(
        issuer
    ).public_key(
        private_key.public_key()
    ).serial_number(
        x509.random_serial_number()
    ).not_valid_before(
        datetime.utcnow()
    ).not_valid_after(
        datetime.utcnow() + timedelta(days=365)
    ).add_extension(
        x509.SubjectAlternativeName([x509.DNSName("localhost")]),
        critical=False,
    ).sign(private_key, hashes.SHA256(), default_backend())
    
    return private_key, cert

